+        let num_steps = workflow.step_count();
+        let mut step = 0usize;
+        let result = loop {
+            let r = workflow.execute_step(&mut ctx, step).await;
+            match r {
+                StepResult::JumpTo { step: target } => step = target,
+                StepResult::Continue if step + 1 < num_steps => step += 1,
+                other => break other,
+            }
+        };
